import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { searchWorkers, getRoom } from '../utils/api';
import useLocation from '../hooks/useLocation';

const WORK_TYPES = [
  'all', 'plumber', 'electrician', 'driver', 'helper', 'carpenter',
  'painter', 'cleaner', 'cook', 'security', 'gardener', 'other',
];

const Workers = () => {
  const [workers, setWorkers] = useState([]);
  const [workType, setWorkType] = useState('all');
  const [search, setSearch] = useState('');
  const [loading, setLoading] = useState(false);

  const { location } = useLocation();
  const navigate = useNavigate();

  const load = async () => {
    if (!location) return;
    setLoading(true);
    try {
      const params = {
        lat: location.lat,
        lng: location.lng,
        radius: 10,
      };

      if (workType !== 'all') params.workType = workType;

      const res = await searchWorkers(params);
      setWorkers(res.data);
    } catch (err) {
      console.log(err);
    }
    setLoading(false);
  };

  useEffect(() => {
    load();
  }, [location, workType]);

  const handleMessage = async (wId) => {
    try {
      const res = await getRoom(wId);
      navigate(`/chat/${res.data.roomId}/${wId}`);
    } catch (err) {
      console.log(err);
    }
  };

  // 🔍 SEARCH FILTER (frontend)
  const filteredWorkers = workers.filter((w) =>
    w.name?.toLowerCase().includes(search.toLowerCase())
  );

  return (
    <div className="page">

      {/* HEADER */}
      <div className="section-title">👷 Workers Nearby</div>

      {/* 🔍 SEARCH + FILTER ROW */}
      <div style={{
        display: 'flex',
        gap: 10,
        marginBottom: 16,
        flexWrap: 'wrap'
      }}>

        {/* Search */}
        <input
          type="text"
          placeholder="Search worker..."
          value={search}
          onChange={(e) => setSearch(e.target.value)}
          className="form-input"
          style={{ flex: 1, minWidth: 200 }}
        />

        {/* Filter */}
        <div style={{ position: 'relative' }}>
          <select
            className="form-select"
            value={workType}
            onChange={(e) => setWorkType(e.target.value)}
            style={{ minWidth: 180 }}
          >
            {WORK_TYPES.map((w) => (
              <option key={w} value={w}>
                {w === 'all' ? 'All Categories' : w.charAt(0).toUpperCase() + w.slice(1)}
              </option>
            ))}
          </select>
        </div>

      </div>

      {/* CONTENT */}
      {loading ? (
        <div className="loading">
          <div className="spinner" />
        </div>
      ) : filteredWorkers.length === 0 ? (
        <div className="empty-state">
          <div className="empty-icon">🔍</div>
          <p>No workers found</p>
        </div>
      ) : (
        filteredWorkers.map((w) => (
          <div
            key={w._id}
            className="card"
            style={{
              padding: 14,
              display: 'flex',
              gap: 12,
              alignItems: 'center'
            }}
          >

            {/* Avatar */}
            {w.profilePhoto ? (
              <img
                src={w.profilePhoto}
                alt={w.name}
                style={{
                  width: 60,
                  height: 60,
                  borderRadius: '50%',
                  objectFit: 'cover'
                }}
              />
            ) : (
              <div
                className="avatar-placeholder"
                style={{ width: 60, height: 60, fontSize: '1.3rem' }}
              >
                {w.name?.[0]?.toUpperCase()}
              </div>
            )}

            {/* Info */}
            <div
              onClick={() => navigate(`/profile/${w._id}`)}
              style={{ cursor: 'pointer', flex: 1 }}
            >
              <div style={{ fontWeight: 700 }}>{w.name}</div>

              <div className="profile-badge" style={{ margin: '4px 0' }}>
                {w.workType}
              </div>

              <div style={{
                display: 'flex',
                gap: 12,
                fontSize: '0.8rem',
                color: 'var(--mid)'
              }}>
                <span>⭐ {w.rating?.toFixed(1) || 'New'}</span>
                <span>📍 {w.distance} km</span>
              </div>
            </div>

            {/* Chat */}
            <button
              className="btn btn-primary btn-sm"
              onClick={() => handleMessage(w._id)}
            >
              💬
            </button>

          </div>
        ))
      )}
    </div>
  );
};

export default Workers;
